```class Solution {
public:
    string originalDigits(string s) {
        vector<int> nums;
        for (char c : s) {
            if (isDigit(c)) {
                int num = c - '0';
                nums.push_back(num);
            }
        }
        string result;
        for (int num : nums) {
            result += num;
        }
        return result;
    }

    bool isDigit(char c) {
        return ('0' <= c && c <= '9');
    }
};
```

